import { Component } from '@angular/core';
import { Form, FormGroup, FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { UserService } from '../../services/users.service';

@Component({
  selector: 'app-signup',
  imports: [ReactiveFormsModule, RouterLink],
  templateUrl: './signup.html',
  styleUrls: ['./signup.css'],
  standalone: true
})
export class Signup {

  signupForm: FormGroup;
  public token: string = "";
  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly router: Router,
    private readonly userService: UserService,
  ) {

    this.signupForm = this.formBuilder.group({
      email: ['', Validators.required],
      password: ['', Validators.required]
    });

  }

  signup() {

    const thisUser = {
      id: "e17bb89d-516b-4d23-9e44-3b17b31668e0",
      email: this.signupForm.get('email')?.value,
      password: this.signupForm.get('password')?.value
    };

    const jsonString: string = JSON.stringify(thisUser);
    console.log('to signup...name:' + jsonString);

          
    this.userService.signup(
      {
        id: "e17bb89d-516b-4d23-9e44-3b17b31668e0",
        email: this.signupForm.get('email')?.value,
        password: this.signupForm.get('password')?.value
      }
    ).subscribe((data) => {
      if (data) {
        this.token = data;

        console.log("Successfully signed up...token:" + data);

        //this.router.navigate(['/invoice-list']);
      } else {
        console.log("Something went wrong...");
      }
    });
  }


  testEndPoint() {
    this.userService.test().subscribe((data) => {
      if (data) {
        this.token = data;

        console.log("test...:" + data);
      } else {
        console.log("Something went wrong...");
      }
    });
  }

}
<div class="card shadow-sm">
  <div class="card-header bg-lightly py-3">
    <h3 class="card-title">
      Register User
    </h3>
    <span>{{token ? "logged in" : "not logged"}}</span>
  </div>

  <div class="card-body p-4">
    <form [formGroup]="signupForm" (ngSubmit)="signup()" class="py-2">

      <div class="form-group">
        <label for="email">Email</label>
        <input type="email" class="form-control" formControlName="email" placeholder="user@company.co.za">
      </div>

      <div class="form-group">
        <label for="password">Password</label>
        <input type="text" class="form-control" formControlName="password" placeholder="Us3r0n3">
      </div>

      <div class="row form-group py-4">
        <button type="submit"
                class="btn btn-primary col-md-3"
                [disabled]="!signupForm.valid">
                Submit
        </button>

        <a class="nav-link px-2 link-secondary col-md-3 "
           [routerLink]="['/customer-list']">
                Cancel
        </a>
      </div>
    </form>
  </div>
</div>
